     1тЖТ/**
     2тЖТ * MMS REST API
     3тЖТ *
     4тЖТ * Main Hono application setup with middleware and route registration.
     5тЖТ * Provides RESTful endpoints for the Metro Fleet Mileage Management System.
     6тЖТ *
     7тЖТ * Base URL: /api/v1
     8тЖТ * Authentication: Bearer JWT
     9тЖТ * Rate Limiting: 100 requests/minute per user (Redis sliding window)
    10тЖТ *
    11тЖТ * @see specs/005-api.md
    12тЖТ */
    13тЖТ
    14тЖТimport { Hono } from 'hono';
    15тЖТimport { cors } from 'hono/cors';
    16тЖТimport { logger as honoLogger } from 'hono/logger';
    17тЖТimport { secureHeaders } from 'hono/secure-headers';
    18тЖТimport { timing } from 'hono/timing';
    19тЖТimport {
    20тЖТ  requestContext,
    21тЖТ  createErrorHandler,
    22тЖТ  notFoundHandler,
    23тЖТ  tracingMiddleware,
    24тЖТ  rateLimiter,
    25тЖТ  strictRateLimiter,
    26тЖТ} from './middleware';
    27тЖТimport { authRoutes, fleetRoutes, pmScheduleRoutes, mileageRoutes, optimizerRoutes, baselineRoutes, driftRoutes, manhourRoutes, canvasRoutes, costingRoutes, materialRoutes, scenarioRoutes, exportRoutes, integrationRoutes, baselineAssumptionRoutes } from './routes';
    28тЖТimport { success, type AppVariables } from './types';
    29тЖТimport { logger } from '../lib/logging/logger';
    30тЖТimport { createOpenApiRoutes } from './openapi';
    31тЖТimport { getMetrics, getMetricsContentType } from '../lib/metrics';
    32тЖТimport { checkDatabaseHealth } from '../lib/db/connection';
    33тЖТimport { checkRedisHealth } from '../lib/redis/connection';
    34тЖТ
    35тЖТ/**
    36тЖТ * Create the main Hono application
    37тЖТ */
    38тЖТexport function createApp(): Hono<{ Variables: AppVariables }> {
    39тЖТ  const app = new Hono<{ Variables: AppVariables }>();
    40тЖТ
    41тЖТ  // ==========================================================================
    42тЖТ  // Global Middleware
    43тЖТ  // ==========================================================================
    44тЖТ
    45тЖТ  // Security headers
    46тЖТ  app.use('*', secureHeaders());
    47тЖТ
    48тЖТ  // CORS configuration
    49тЖТ  app.use(
    50тЖТ    '*',
    51тЖТ    cors({
