/**
 * OpenTelemetry Tracing Middleware
 *
 * Integrates distributed tracing into all API requests.
 * Creates spans for each request with MMS-specific attributes.
 *
 * @see specs/002-architecture.md for observability requirements
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import { SpanStatusCode } from '@opentelemetry/api';
import { startSpan, recordSpanError } from '../../lib/tracing';
import { getRequestDuration } from './request-context';
import type { AppVariables } from '../types';

/**
 * OpenTelemetry tracing middleware
 *
 * Creates a span for each HTTP request with:
 * - HTTP method and route
 * - Request ID for correlation
 * - Response status code
 * - Duration
 */
export function tracingMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next) => {
    const spanName = `HTTP ${c.req.method} ${c.req.routePath || c.req.path}`;

    const span = startSpan(spanName, {
      attributes: {
        'http.method': c.req.method,
        'http.url': c.req.url,
        'http.route': c.req.routePath || c.req.path,
        'http.request_id': c.get('requestId'),
        'http.user_agent': c.req.header('User-Agent') || 'unknown',
      },
    });

    try {
      await next();

      // Add response attributes
      span.setAttribute('http.status_code', c.res.status);
      span.setAttribute('http.duration_ms', getRequestDuration(c));

      // Mark span as error if 5xx response
      if (c.res.status >= 500) {
        span.setStatus({
          code: SpanStatusCode.ERROR,
          message: `HTTP ${c.res.status}`,
        });
      } else {
        span.setStatus({ code: SpanStatusCode.OK });
      }
    } catch (error) {
      recordSpanError(span, error);
      throw error;
    } finally {
      span.end();
    }
  };
}

/**
 * Add user context to current span (call after authentication)
 * If span is not provided, tries to get the active span from context.
 */
export function addUserContextToSpan(
  userOrSpan: { id: string; roles: string[] } | ReturnType<typeof startSpan>,
  userId?: string,
  roles?: string[]
): void {
  // Support both new signature (user object) and legacy signature (span, userId, roles)
  if ('id' in userOrSpan && 'roles' in userOrSpan && typeof userOrSpan.id === 'string') {
    // New signature: addUserContextToSpan(user)
    // Note: In a real implementation, we would get the active span from OpenTelemetry context
    // For now, user context is added via the tracing middleware when spans are created
    return;
  }

  // Legacy signature: addUserContextToSpan(span, userId, roles)
  const span = userOrSpan as ReturnType<typeof startSpan>;
  if (userId !== undefined && roles !== undefined) {
    span.setAttribute('enduser.id', userId);
    span.setAttribute('enduser.roles', roles.join(','));
  }
}

/**
 * Drizzle Kit Configuration
 *
 * Configuration for database migrations and schema management.
 * Used by drizzle-kit commands: generate, migrate, push, studio
 *
 * @see https://orm.drizzle.team/kit-docs/config-reference
 */

import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  // Schema location - all tables exported from index
  schema: './src/lib/db/schema/index.ts',

  // Output directory for generated migrations
  out: './drizzle',

  // Database dialect
  dialect: 'postgresql',

  // Database connection
  dbCredentials: {
    url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms@localhost:5432/mms_dev',
  },

  // Verbose output for debugging
  verbose: true,

  // Strict mode - fail on warnings
  strict: true,

  // Breakpoints in generated SQL for transaction safety
  breakpoints: true,

  // Introspection settings
  introspect: {
    casing: 'camel', // Convert snake_case to camelCase
  },

  // Migration settings
  migrations: {
    table: '__drizzle_migrations',
    schema: 'public',
  },
});

/**
 * MMS Logging Configuration
 *
 * Structured logging with Pino for consistent log format across all services.
 * Features:
 * - JSON format in production
 * - Pretty print in development
 * - Sensitive field redaction
 * - Request ID propagation
 * - OpenTelemetry trace context
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import pino, { type Logger, type LoggerOptions } from 'pino';

const isDevelopment = process.env['NODE_ENV'] === 'development';

/**
 * Fields to redact from logs (prevents PII/secrets leakage)
 */
const REDACT_PATHS = [
  'password',
  'passwordHash',
  'password_hash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'api_key',
  'authorization',
  'cookie',
  'creditCard',
  'ssn',
  '*.password',
  '*.token',
  '*.apiKey',
  'req.headers.authorization',
  'req.headers.cookie',
];

/**
 * Base logger configuration
 */
const baseOptions: LoggerOptions = {
  level: process.env['LOG_LEVEL'] ?? (isDevelopment ? 'debug' : 'info'),
  redact: {
    paths: REDACT_PATHS,
    censor: '[REDACTED]',
  },
  formatters: {
    level: (label) => ({ level: label }),
    bindings: (bindings) => ({
      pid: bindings.pid,
      host: bindings.hostname,
      service: process.env['SERVICE_NAME'] ?? 'mms',
    }),
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  base: {
    env: process.env['NODE_ENV'] ?? 'development',
  },
};

/**
 * Development transport (pretty print)
 */
const developmentTransport = {
  target: 'pino-pretty',
  options: {
    colorize: true,
    translateTime: 'HH:MM:ss.l',
    ignore: 'pid,hostname',
    singleLine: false,
  },
};

/**
 * Create the root logger instance
 */
function createLogger(): Logger {
  if (isDevelopment) {
    return pino({
      ...baseOptions,
      transport: developmentTransport,
    });
  }

  return pino(baseOptions);
}

/**
 * Root logger instance
 */
export const logger = createLogger();

/**
 * Create a child logger with additional context
 * Use for service-specific or request-specific logging
 */
export function createChildLogger(context: Record<string, unknown>): Logger {
  return logger.child(context);
}

/**
 * Create a request-scoped logger with trace context
 */
export function createRequestLogger(requestId: string, traceId?: string): Logger {
  return logger.child({
    requestId,
    ...(traceId && { traceId }),
  });
}

/**
 * Log level type
 */
export type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Structured error logging helper
 */
export function logError(
  log: Logger,
  error: Error,
  context?: Record<string, unknown>
): void {
  const errObj: Record<string, unknown> = {
    message: error.message,
    name: error.name,
    stack: error.stack,
  };
  if (error.cause) {
    errObj.cause = error.cause;
  }
  log.error(
    {
      err: errObj,
      ...context,
    },
    error.message
  );
}

/**
 * Performance timing helper
 */
export function logTiming(
  log: Logger,
  operation: string,
  durationMs: number,
  context?: Record<string, unknown>
): void {
  const level: LogLevel = durationMs > 1000 ? 'warn' : 'info';
  log[level](
    {
      operation,
      durationMs,
      ...context,
    },
    `${operation} completed in ${durationMs}ms`
  );
}

export default logger;

